DROP TABLE IF EXISTS `customer_delivery_subscriptions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `customer_delivery_subscriptions` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `customer_id` bigint NOT NULL,
  `meal_slot_order_id` bigint NOT NULL,
  `template_id` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL,
  `status` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL,
  `source` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `authorized_at` datetime NOT NULL,
  `sent_at` datetime DEFAULT NULL,
  `last_error_message` varchar(512) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_customer_delivery_subscriptions_order` (`meal_slot_order_id`),
  KEY `idx_customer_delivery_subscriptions_customer_status` (`customer_id`,`status`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

LOCK TABLES `customer_delivery_subscriptions` WRITE;
/*!40000 ALTER TABLE `customer_delivery_subscriptions` DISABLE KEYS */;
/*!40000 ALTER TABLE `customer_delivery_subscriptions` ENABLE KEYS */;
