DROP TABLE IF EXISTS `customer_notes`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `customer_notes` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `customer_id` bigint NOT NULL,
  `note_type` varchar(16) COLLATE utf8mb4_unicode_ci NOT NULL,
  `scope_type` varchar(16) COLLATE utf8mb4_unicode_ci NOT NULL,
  `content` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `start_at` timestamp NULL DEFAULT NULL,
  `end_at` timestamp NULL DEFAULT NULL,
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `display_order` int NOT NULL DEFAULT '0',
  `created_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `updated_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_customer_notes_customer` (`customer_id`),
  KEY `idx_customer_notes_lookup` (`customer_id`,`note_type`,`scope_type`,`is_active`),
  CONSTRAINT `chk_customer_notes_scope_time` CHECK ((((`scope_type` = _utf8mb4'LONG_TERM') and (`start_at` is null) and (`end_at` is null)) or ((`scope_type` = _utf8mb4'TIME_BOXED') and (`start_at` is not null) and (`end_at` is not null))))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

LOCK TABLES `customer_notes` WRITE;
/*!40000 ALTER TABLE `customer_notes` DISABLE KEYS */;
/*!40000 ALTER TABLE `customer_notes` ENABLE KEYS */;
UNLOCK TABLES;
DROP TABLE IF EXISTS `customers`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `customers` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `name` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `phone` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL,
  `source` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL,
  `active` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `openid` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `session_key` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `profile_completed` tinyint(1) DEFAULT '0',
  `customer_status` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'INTENTION',
  `registered_at` timestamp NULL DEFAULT NULL,
  `first_paid_at` timestamp NULL DEFAULT NULL,
  `last_order_at` timestamp NULL DEFAULT NULL,
  `last_login_at` timestamp NULL DEFAULT NULL,
  `source_channel` varchar(32) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `merchant_remark` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `current_openid` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `openid_updated_at` timestamp NULL DEFAULT NULL,
  `is_priority_customer` tinyint(1) NOT NULL DEFAULT '0',
  `priority_tag` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `priority_note` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `phone` (`phone`),
  UNIQUE KEY `uk_customers_name_active` (`name`,`active`),
  UNIQUE KEY `uk_customers_openid` (`openid`)
) ENGINE=InnoDB AUTO_INCREMENT=913 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

